using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using McpServer.Tools;
using McpServer.Prompts;

var builder = Host.CreateApplicationBuilder(args);

// Send all logging to stderr so it never contaminates the stdio JSON-RPC channel.
builder.Logging.ClearProviders();
builder.Logging.AddConsole(opts => opts.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient("api", client =>
{
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "McpServer", Version = "1.0.0" };
    })
    .WithStdioServerTransport()
    .WithTools<ApiTool>()
    .WithPrompts<SummarizePrompt>();

var app = builder.Build();
await app.RunAsync();

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTool
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the JSON response.")]
    public static async Task<string> FetchApi(
        IHttpClientFactory httpClientFactory,
        [Description("The full URL of the API endpoint to call.")] string url,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("api");
        using var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var stream = await response.Content.ReadAsStreamAsync(cancellationToken);
        var json = await JsonDocument.ParseAsync(stream, cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IEnumerable<PromptMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional maximum number of sentences for the summary.")] int? maxSentences = null)
    {
        var constraint = maxSentences.HasValue
            ? $" Limit your summary to {maxSentences.Value} sentence(s)."
            : string.Empty;

        yield return new PromptMessage
        {
            Role = Role.User,
            Content = new Content
            {
                Type = "text",
                Text = $"Please provide a concise summary of the following text.{constraint}\n\n{text}",
            },
        };
    }
}

